// RATIONAL FUNCTIONS
// ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ
{
  const S = ["rational-functions"];
  const mcq: MCQ[] = [
    { content: "The vertical asymptote of $y = \\dfrac{1}{x}$ is:", optionA: "$x = 0$", optionB: "$y = 0$", optionC: "$x = 1$", optionD: "$y = 1$", correctOption: "A", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Denominator $x = 0$ gives vertical asymptote $x = 0$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "The horizontal asymptote of $y = \\dfrac{1}{x}$ is:", optionA: "$x = 0$", optionB: "$y = 0$", optionC: "$y = 1$", optionD: "$y = \\infty$", correctOption: "B", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** As $x \\to \\pm \\infty$, $1/x \\to 0$. Horizontal asymptote $y = 0$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "The domain of $y = \\dfrac{1}{x - 3}$ is:", optionA: "$\\mathbb{R}$", optionB: "$\\mathbb{R} \\setminus \\{0\\}$", optionC: "$\\mathbb{R} \\setminus \\{3\\}$", optionD: "$(3, \\infty)$", correctOption: "C", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Denominator zero at $x = 3$, so domain excludes $3$.\n\n**Answer: C**", subtopicSlugs: S },
    { content: "$y = \\dfrac{2}{x}$ compared to $y = \\dfrac{1}{x}$ is:", optionA: "Translated right", optionB: "Dilated by $2$ from $x$-axis", optionC: "Reflected in $x$-axis", optionD: "Reflected in $y$-axis", correctOption: "B", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Multiplying by $2$ is a vertical dilation with factor $2$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "$\\lim_{x \\to \\infty} \\dfrac{3}{x}$ equals:", optionA: "$0$", optionB: "$1$", optionC: "$3$", optionD: "$\\infty$", correctOption: "A", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** As $x \\to \\infty$, $3/x \\to 0$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "The graph of $y = -\\dfrac{1}{x}$ lies in quadrants:", optionA: "I and II", optionB: "I and III", optionC: "II and IV", optionD: "II and III", correctOption: "C", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** For $x > 0$, $y < 0$ (quadrant IV); for $x < 0$, $y > 0$ (quadrant II).\n\n**Answer: C**", subtopicSlugs: S },
    // Medium
    { content: `${graphImage((x) => 1 / x, { xMin: -5, xMax: 5, yMin: -5, yMax: 5 }, "y=1/x")}\n\nThe graph shows $y = 1/x$. Which statement is true?`, optionA: "Domain is $\\mathbb{R}$", optionB: "It has a $y$-intercept", optionC: "It is not defined at $x = 0$", optionD: "It is linear", correctOption: "C", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $1/0$ is undefined, so there is no $y$-intercept and $x = 0$ is excluded.\n\n**Answer: C**", subtopicSlugs: S },
    { content: "The horizontal asymptote of $y = \\dfrac{2x + 1}{x - 3}$ is:", optionA: "$y = 2$", optionB: "$y = -1$", optionC: "$y = 1/3$", optionD: "$y = 0$", correctOption: "A", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Ratio of leading coefficients $= 2/1 = 2$, so $y = 2$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "Divide: $\\dfrac{x + 3}{x - 1} = 1 + \\dfrac{?}{x - 1}$. The missing numerator is:", optionA: "$2$", optionB: "$3$", optionC: "$4$", optionD: "$x + 2$", correctOption: "C", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $\\dfrac{x + 3}{x - 1} = \\dfrac{(x - 1) + 4}{x - 1} = 1 + \\dfrac{4}{x - 1}$.\n\n**Answer: C**", subtopicSlugs: S },
    { content: `${graphImage((x) => 1 / (x - 2), { xMin: -2, xMax: 6, yMin: -5, yMax: 5 }, "y=1/(x-2)")}\n\nThe vertical asymptote of the graph is:`, optionA: "$x = 0$", optionB: "$x = 1$", optionC: "$x = 2$", optionD: "$x = -2$", correctOption: "C", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Denominator $x - 2 = 0$ at $x = 2$.\n\n**Answer: C**", subtopicSlugs: S },
    { content: "The range of $y = \\dfrac{1}{x} + 3$ is:", optionA: "$\\mathbb{R}$", optionB: "$\\mathbb{R} \\setminus \\{0\\}$", optionC: "$\\mathbb{R} \\setminus \\{3\\}$", optionD: "$(3, \\infty)$", correctOption: "C", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $1/x \\neq 0$, so $y \\neq 3$. All other values occur.\n\n**Answer: C**", subtopicSlugs: S },
    { content: "The $y$-intercept of $y = \\dfrac{2x + 4}{x - 1}$ is:", optionA: "$y = -4$", optionB: "$y = 4$", optionC: "$y = -2$", optionD: "$y = 2$", correctOption: "A", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** At $x = 0$: $\\dfrac{0 + 4}{0 - 1} = -4$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: `The table shows values of $f(x) = \\dfrac{1}{x - 2}$.\n\n| $x$ | $0$ | $1$ | $1.5$ | $3$ | $4$ |\n|---|---|---|---|---|---|\n| $f(x)$ | $-0.5$ | $-1$ | $-2$ | $1$ | $0.5$ |\n\nAs $x \\to 2^-$, $f(x)$:`, optionA: "$\\to 0$", optionB: "$\\to \\infty$", optionC: "$\\to -\\infty$", optionD: "$\\to 2$", correctOption: "C", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** From below $x = 2$, $x - 2 \\to 0^-$, so $1/(x - 2) \\to -\\infty$.\n\n**Answer: C**", subtopicSlugs: S },
    { content: "The $x$-intercept of $y = \\dfrac{x - 5}{x + 2}$ is:", optionA: "$x = -2$", optionB: "$x = 0$", optionC: "$x = 2$", optionD: "$x = 5$", correctOption: "D", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Numerator $= 0$ at $x = 5$ (denominator nonzero there).\n\n**Answer: D**", subtopicSlugs: S },
    { content: "Write $\\dfrac{3x + 5}{x + 1}$ in the form $A + \\dfrac{B}{x + 1}$. Then $(A, B) = $:", optionA: "$(3, 2)$", optionB: "$(3, 5)$", optionC: "$(1, 3)$", optionD: "$(5, 3)$", correctOption: "A", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $\\dfrac{3x + 5}{x + 1} = \\dfrac{3(x + 1) + 2}{x + 1} = 3 + \\dfrac{2}{x + 1}$. So $(A, B) = (3, 2)$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "The function $y = \\dfrac{1}{x^2}$ has:", optionA: "Range $\\mathbb{R}$", optionB: "Range $(0, \\infty)$", optionC: "No asymptote", optionD: "$x$-intercept at $x = 0$", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $1/x^2 > 0$ always (when defined), so range is $(0, \\infty)$.\n\n**Answer: B**", subtopicSlugs: S },
    // Hard
    { content: "The partial fractions of $\\dfrac{5x - 7}{(x - 1)(x - 2)}$ are $\\dfrac{A}{x - 1} + \\dfrac{B}{x - 2}$ with:", optionA: "$A = 2, B = 3$", optionB: "$A = -2, B = 3$", optionC: "$A = 2, B = -3$", optionD: "$A = -2, B = -3$", correctOption: "A", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** Cover-up: $A = \\dfrac{5(1) - 7}{1 - 2} = \\dfrac{-2}{-1} = 2$. $B = \\dfrac{5(2) - 7}{2 - 1} = 3$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "The horizontal asymptote of $y = \\dfrac{3 x^2 + 1}{x^2 - 4}$ is:", optionA: "$y = 3$", optionB: "$y = 1/4$", optionC: "$y = 0$", optionD: "$y = 1$", correctOption: "A", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** Ratio of leading terms: $3 x^2 / x^2 = 3$, so $y = 3$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "The function $y = \\dfrac{x^2 - 4}{x - 2}$ simplifies for $x \\neq 2$ to:", optionA: "$x + 2$", optionB: "$x - 2$", optionC: "$\\dfrac{1}{x - 2}$", optionD: "$x^2$", correctOption: "A", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** $x^2 - 4 = (x - 2)(x + 2)$. Cancel $(x - 2)$: $y = x + 2$ for $x \\neq 2$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "The graph of $y = \\dfrac{1}{x - 3} + 2$ has asymptotes at:", optionA: "$x = 3, y = 2$", optionB: "$x = 2, y = 3$", optionC: "$x = -3, y = -2$", optionD: "$x = 0, y = 0$", correctOption: "A", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** Vertical asymptote at $x = 3$ (from the denominator). Horizontal asymptote at $y = 2$ (from the vertical shift).\n\n**Answer: A**", subtopicSlugs: S },
  ];
  const shortAnswer: FR[] = [
    { content: "State the domain and the vertical asymptote of $y = \\dfrac{1}{x + 4}$.", marks: 2, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Denominator zero at $x = -4$, so domain is $\\mathbb{R} \\setminus \\{-4\\}$.\n\n**Step 2 (1 mark):** Vertical asymptote $x = -4$.", subtopicSlugs: S },
    { content: "Find the $x$- and $y$-intercepts of $y = \\dfrac{x - 2}{x + 1}$.", marks: 2, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** $x$-intercept: numerator zero at $x = 2$.\n\n**Step 2 (1 mark):** $y$-intercept: $y(0) = -2/1 = -2$.", subtopicSlugs: S },
    { content: "Write $\\dfrac{2x + 5}{x - 3}$ in the form $A + \\dfrac{B}{x - 3}$.", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Manipulate the numerator to match the denominator.\n\n$$2x + 5 = 2(x - 3) + 11.$$\n\n**Step 2 (1 mark):** Divide.\n\n$$\\dfrac{2x + 5}{x - 3} = 2 + \\dfrac{11}{x - 3}.$$\n\n**Step 3 (1 mark):** So $A = 2$, $B = 11$.", subtopicSlugs: S },
    { content: "Sketch $y = \\dfrac{1}{x - 2}$, labelling asymptotes and any intercepts.", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Vertical asymptote $x = 2$; horizontal asymptote $y = 0$.\n\n**Step 2 (1 mark):** $y$-intercept at $(0, -1/2)$; no $x$-intercept.\n\n**Step 3 (1 mark):** Two branches: for $x > 2$, curve decreases from $\\infty$ to $0$; for $x < 2$, curve goes from $0$ to $-\\infty$.", subtopicSlugs: S },
    { content: "Find the asymptotes of $y = \\dfrac{3x}{x + 2}$.", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Vertical: denominator zero at $x = -2$.\n\n**Step 2 (1 mark):** Horizontal: ratio of leading coefficients $= 3/1 = 3$.\n\n**Step 3 (1 mark):** So $x = -2$ and $y = 3$.", subtopicSlugs: S },
    { content: "Solve $\\dfrac{1}{x - 1} = 2$.", marks: 2, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Cross-multiply.\n\n$$1 = 2(x - 1) = 2x - 2.$$\n\n**Step 2 (1 mark):** Solve: $2x = 3$, so $x = 3/2$.", subtopicSlugs: S },
    { content: "Decompose $\\dfrac{3x + 2}{(x - 1)(x + 2)}$ into partial fractions.", marks: 4, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** Write $\\dfrac{3x + 2}{(x - 1)(x + 2)} = \\dfrac{A}{x - 1} + \\dfrac{B}{x + 2}$.\n\n**Step 2 (1 mark):** Clear denominators.\n\n$$3x + 2 = A(x + 2) + B(x - 1).$$\n\n**Step 3 (1 mark):** Let $x = 1$: $5 = 3A$, so $A = 5/3$.\n\n**Step 4 (1 mark):** Let $x = -2$: $-4 = -3B$, so $B = 4/3$. Hence $\\dfrac{5/3}{x - 1} + \\dfrac{4/3}{x + 2}$.", subtopicSlugs: S },
    { content: "State the domain and range of $y = \\dfrac{2}{x - 1} + 3$.", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Domain: $x \\neq 1$, so $\\mathbb{R} \\setminus \\{1\\}$.\n\n**Step 2 (1 mark):** Horizontal asymptote $y = 3$; $\\dfrac{2}{x - 1}$ never equals $0$.\n\n**Step 3 (1 mark):** Range: $\\mathbb{R} \\setminus \\{3\\}$.", subtopicSlugs: S },
    { content: "Solve $\\dfrac{x + 1}{x - 2} = 3$.", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Cross-multiply (valid for $x \\neq 2$).\n\n$$x + 1 = 3(x - 2).$$\n\n**Step 2 (1 mark):** Expand.\n\n$$x + 1 = 3x - 6.$$\n\n**Step 3 (1 mark):** Solve: $-2x = -7$, so $x = 7/2$.", subtopicSlugs: S },
    { content: "A rectangle has area $12$ cm$^2$ and width $w$ cm. Find an expression for the length $L$, and compute $L$ when $w = 3$.", marks: 3, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** $L = 12/w$.\n\n**Step 2 (1 mark):** Substitute $w = 3$.\n\n$$L = 12/3.$$\n\n**Step 3 (1 mark):** $L = 4$ cm.", subtopicSlugs: S },
  ];
  const extendedResponse: FR[] = [
    { content: "Consider $f(x) = \\dfrac{2x + 3}{x - 1}$.\n\n**a.** State the domain. (1 mark)\n\n**b.** Find the $x$- and $y$-intercepts. (2 marks)\n\n**c.** Find both asymptotes. (2 marks)\n\n**d.** Write $f(x)$ in the form $A + \\dfrac{B}{x - 1}$. (3 marks)\n\n**e.** Hence state the range of $f$. (3 marks)", marks: 11, difficulty: "HARD", solutionContent: "**a. (1 mark)**\n\n*Step 1 (1 mark):* Domain $\\mathbb{R} \\setminus \\{1\\}$.\n\n**b. (2 marks)**\n\n*Step 1 (1 mark):* $x$-intercept: $2x + 3 = 0 \\Rightarrow x = -3/2$.\n\n*Step 2 (1 mark):* $y$-intercept: $f(0) = 3/(-1) = -3$.\n\n**c. (2 marks)**\n\n*Step 1 (1 mark):* Vertical: $x = 1$.\n\n*Step 2 (1 mark):* Horizontal: $y = 2$ (leading ratio).\n\n**d. (3 marks)**\n\n*Step 1 (1 mark):* $2x + 3 = 2(x - 1) + 5$.\n\n*Step 2 (1 mark):* Divide.\n\n$$f(x) = 2 + \\dfrac{5}{x - 1}.$$\n\n*Step 3 (1 mark):* So $A = 2$, $B = 5$.\n\n**e. (3 marks)**\n\n*Step 1 (1 mark):* $\\dfrac{5}{x - 1} \\neq 0$ for any $x$.\n\n*Step 2 (1 mark):* So $f(x) \\neq 2$ but takes all other real values.\n\n*Step 3 (1 mark):* Range $\\mathbb{R} \\setminus \\{2\\}$.", subtopicSlugs: S },
    { content: "Let $f(x) = \\dfrac{1}{x^2 - 4}$.\n\n**a.** State the domain. (2 marks)\n\n**b.** Find the vertical asymptotes. (2 marks)\n\n**c.** Find the horizontal asymptote. (1 mark)\n\n**d.** Determine the sign of $f$ on $(-2, 2)$. (2 marks)\n\n**e.** Solve $f(x) = 1$. (3 marks)", marks: 10, difficulty: "HARD", solutionContent: "**a. (2 marks)**\n\n*Step 1 (1 mark):* Denominator zero at $x^2 = 4$, so $x = \\pm 2$.\n\n*Step 2 (1 mark):* Domain $\\mathbb{R} \\setminus \\{-2, 2\\}$.\n\n**b. (2 marks)**\n\n*Step 1 (1 mark):* As $x \\to 2$, $1/(x^2 - 4) \\to \\pm \\infty$.\n\n*Step 2 (1 mark):* Similarly at $x = -2$. Asymptotes: $x = \\pm 2$.\n\n**c. (1 mark)**\n\n*Step 1 (1 mark):* As $x \\to \\pm\\infty$, $f \\to 0$. Asymptote $y = 0$.\n\n**d. (2 marks)**\n\n*Step 1 (1 mark):* On $(-2, 2)$, $x^2 < 4$, so $x^2 - 4 < 0$.\n\n*Step 2 (1 mark):* $f(x) < 0$ on $(-2, 2)$.\n\n**e. (3 marks)**\n\n*Step 1 (1 mark):* $x^2 - 4 = 1$.\n\n*Step 2 (1 mark):* $x^2 = 5$.\n\n*Step 3 (1 mark):* $x = \\pm \\sqrt{5}$.", subtopicSlugs: S },
    { content: "Consider the rational function $f(x) = \\dfrac{3}{x - 2} + 1$.\n\n**a.** State the asymptotes. (2 marks)\n\n**b.** Find the $x$-intercept. (2 marks)\n\n**c.** Find the $y$-intercept. (1 mark)\n\n**d.** State the domain and range. (2 marks)\n\n**e.** Describe the transformations from $y = 1/x$. (3 marks)\n\n**f.** Sketch the graph. (2 marks)", marks: 12, difficulty: "HARD", solutionContent: "**a. (2 marks)**\n\n*Step 1 (1 mark):* Vertical asymptote $x = 2$.\n\n*Step 2 (1 mark):* Horizontal asymptote $y = 1$.\n\n**b. (2 marks)**\n\n*Step 1 (1 mark):* Set $\\dfrac{3}{x - 2} = -1$.\n\n*Step 2 (1 mark):* $x - 2 = -3$, so $x = -1$.\n\n**c. (1 mark)**\n\n*Step 1 (1 mark):* $f(0) = -3/2 + 1 = -1/2$.\n\n**d. (2 marks)**\n\n*Step 1 (1 mark):* Domain $\\mathbb{R} \\setminus \\{2\\}$.\n\n*Step 2 (1 mark):* Range $\\mathbb{R} \\setminus \\{1\\}$.\n\n**e. (3 marks)**\n\n*Step 1 (1 mark):* Dilation by factor $3$ from the $x$-axis.\n\n*Step 2 (1 mark):* Translation right by $2$.\n\n*Step 3 (1 mark):* Translation up by $1$.\n\n**f. (2 marks)**\n\n*Step 1 (1 mark):* Sketch two hyperbola branches with asymptotes $x = 2, y = 1$.\n\n*Step 2 (1 mark):* Mark intercepts $(-1, 0)$ and $(0, -1/2)$.", subtopicSlugs: S },
    { content: "Let $f(x) = \\dfrac{x^2 - 1}{x - 1}$ and $g(x) = x + 1$.\n\n**a.** Simplify $f(x)$. (2 marks)\n\n**b.** State any difference between $f$ and $g$. (2 marks)\n\n**c.** Find $f(0)$ and $g(0)$. (2 marks)\n\n**d.** Sketch both graphs on the same axes. (3 marks)\n\n**e.** Solve $f(x) = 5$. (3 marks)", marks: 12, difficulty: "HARD", solutionContent: "**a. (2 marks)**\n\n*Step 1 (1 mark):* Factor $x^2 - 1 = (x - 1)(x + 1)$.\n\n*Step 2 (1 mark):* Cancel $(x - 1)$: $f(x) = x + 1$ for $x \\neq 1$.\n\n**b. (2 marks)**\n\n*Step 1 (1 mark):* $g$ is defined for all $x$; $f$ is not defined at $x = 1$.\n\n*Step 2 (1 mark):* The graph of $f$ has a hole at $(1, 2)$; $g$ does not.\n\n**c. (2 marks)**\n\n*Step 1 (1 mark):* $f(0) = 0 + 1 = 1$ (valid since $0 \\neq 1$).\n\n*Step 2 (1 mark):* $g(0) = 1$.\n\n**d. (3 marks)**\n\n*Step 1 (1 mark):* $g$: straight line with slope $1$, $y$-intercept $1$.\n\n*Step 2 (1 mark):* $f$: same line with an open circle at $(1, 2)$.\n\n*Step 3 (1 mark):* Label the hole.\n\n**e. (3 marks)**\n\n*Step 1 (1 mark):* $f(x) = 5$ iff $x + 1 = 5$ (with $x \\neq 1$).\n\n*Step 2 (1 mark):* $x = 4$.\n\n*Step 3 (1 mark):* Valid since $4 \\neq 1$.", subtopicSlugs: S },
    { content: "Consider $f(x) = \\dfrac{5x - 11}{(x - 1)(x - 3)}$.\n\n**a.** Decompose $f(x)$ into partial fractions. (4 marks)\n\n**b.** State the vertical asymptotes. (2 marks)\n\n**c.** State the horizontal asymptote. (2 marks)\n\n**d.** Find the $x$-intercept. (2 marks)\n\n**e.** Find the $y$-intercept. (3 marks)", marks: 13, difficulty: "HARD", solutionContent: "**a. (4 marks)**\n\n*Step 1 (1 mark):* Write $\\dfrac{5x - 11}{(x - 1)(x - 3)} = \\dfrac{A}{x - 1} + \\dfrac{B}{x - 3}$.\n\n*Step 2 (1 mark):* Clear denominators.\n\n$$5x - 11 = A(x - 3) + B(x - 1).$$\n\n*Step 3 (1 mark):* Let $x = 1$: $-6 = -2A$, so $A = 3$.\n\n*Step 4 (1 mark):* Let $x = 3$: $4 = 2B$, so $B = 2$. Hence $f(x) = \\dfrac{3}{x - 1} + \\dfrac{2}{x - 3}$.\n\n**b. (2 marks)**\n\n*Step 1 (1 mark):* Denominator zero at $x = 1$.\n\n*Step 2 (1 mark):* And $x = 3$.\n\n**c. (2 marks)**\n\n*Step 1 (1 mark):* Degree of numerator $= 1$, degree of denominator $= 2$.\n\n*Step 2 (1 mark):* So $y \\to 0$ at infinity; horizontal asymptote $y = 0$.\n\n**d. (2 marks)**\n\n*Step 1 (1 mark):* Set numerator zero: $5x - 11 = 0$.\n\n*Step 2 (1 mark):* $x = 11/5$.\n\n**e. (3 marks)**\n\n*Step 1 (1 mark):* $f(0) = \\dfrac{-11}{(-1)(-3)}$.\n\n*Step 2 (1 mark):* $= \\dfrac{-11}{3}$.\n\n*Step 3 (1 mark):* $y$-intercept $(0, -11/3)$.", subtopicSlugs: S },
  ];
  writeQset(OUT("rational-functions"), { mcq, shortAnswer, extendedResponse });
}

