{
  const S = ["inverse-functions"];
  const mcq: MCQ[] = [
    { content: "The inverse of $f(x) = x + 5$ is:", optionA: "$f^{-1}(x) = x - 5$", optionB: "$f^{-1}(x) = 5 - x$", optionC: "$f^{-1}(x) = x + 5$", optionD: "$f^{-1}(x) = 1/(x + 5)$", correctOption: "A", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Solve $y = x + 5$ for $x$: $x = y - 5$. Swap notation: $f^{-1}(x) = x - 5$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "A function must be ________ to have an inverse.", optionA: "Continuous", optionB: "Linear", optionC: "One-to-one", optionD: "Even", correctOption: "C", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Inverse exists iff function is one-to-one (injective) on its domain.\n\n**Answer: C**", subtopicSlugs: S },
    { content: "The graph of $y = f^{-1}(x)$ is the reflection of $y = f(x)$ in:", optionA: "$x$-axis", optionB: "$y$-axis", optionC: "Line $y = x$", optionD: "Origin", correctOption: "C", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Inverse reflects across $y = x$.\n\n**Answer: C**", subtopicSlugs: S },
    { content: "The inverse of $f(x) = 2x$ is:", optionA: "$x/2$", optionB: "$2/x$", optionC: "$-2x$", optionD: "$2x$", correctOption: "A", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Solve $y = 2x$: $x = y/2$. So $f^{-1}(x) = x/2$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "If $f^{-1}$ exists, $f(f^{-1}(x))$ equals:", optionA: "$0$", optionB: "$1$", optionC: "$x$", optionD: "$f(x)$", correctOption: "C", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** By definition of inverse.\n\n**Answer: C**", subtopicSlugs: S },
    { content: "The domain of $f^{-1}$ equals:", optionA: "Domain of $f$", optionB: "Range of $f$", optionC: "$\\mathbb{R}$", optionD: "$[0, \\infty)$", correctOption: "B", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Domain and range swap under inversion.\n\n**Answer: B**", subtopicSlugs: S },
    // Medium
    { content: "The inverse of $f(x) = 3x - 4$ is:", optionA: "$(x + 4)/3$", optionB: "$(x - 4)/3$", optionC: "$3x + 4$", optionD: "$3(x - 4)$", correctOption: "A", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $y = 3x - 4 \\Rightarrow x = (y + 4)/3$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "The function $f(x) = x^2$ on $\\mathbb{R}$ has an inverse only if restricted to:", optionA: "$\\mathbb{R}$", optionB: "$[0, \\infty)$", optionC: "$(0, 1)$", optionD: "$[-1, 1]$", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $x^2$ is not one-to-one on $\\mathbb{R}$; restrict to $[0, \\infty)$ (or $(-\\infty, 0]$) to make it invertible.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "The inverse of $f(x) = e^x$ is:", optionA: "$-e^x$", optionB: "$e^{-x}$", optionC: "$\\ln x$", optionD: "$1/e^x$", correctOption: "C", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $y = e^x \\iff x = \\ln y$, so $f^{-1}(x) = \\ln x$.\n\n**Answer: C**", subtopicSlugs: S },
    { content: `${graphImage((x) => x * x, { xMin: 0, xMax: 3, yMin: 0, yMax: 9, marks: [{ x: 2, y: 4, label: "(2, 4)" }] }, "y=x^2 on [0,3]")}\n\nFor $f: [0, 3] \\to \\mathbb{R}$, $f(x) = x^2$, the inverse $f^{-1}$ maps $4$ to:`, optionA: "$2$", optionB: "$\\pm 2$", optionC: "$16$", optionD: "$1/2$", correctOption: "A", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $f^{-1}(x) = \\sqrt{x}$ on the restricted domain. $\\sqrt{4} = 2$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "The inverse of $f(x) = \\dfrac{1}{x}$ (with $x \\neq 0$) is:", optionA: "$x$", optionB: "$-x$", optionC: "$\\dfrac{1}{x}$", optionD: "$-\\dfrac{1}{x}$", correctOption: "C", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $y = 1/x \\iff x = 1/y$, so $f^{-1}(x) = 1/x$ ŌĆö $f$ is its own inverse.\n\n**Answer: C**", subtopicSlugs: S },
    { content: "The inverse of $f(x) = \\sqrt{x}$, $x \\geq 0$, is:", optionA: "$x^2$ for all $x$", optionB: "$x^2$ for $x \\geq 0$", optionC: "$-x^2$", optionD: "$1/\\sqrt{x}$", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Range of $f$ is $[0, \\infty)$, so $f^{-1}(x) = x^2$ with domain $[0, \\infty)$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "If $f(x) = \\ln(x - 1)$, then $f^{-1}(x)$ is:", optionA: "$e^x + 1$", optionB: "$e^{x - 1}$", optionC: "$e^x - 1$", optionD: "$1 - e^x$", correctOption: "A", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $y = \\ln(x - 1) \\iff x - 1 = e^y \\iff x = e^y + 1$. So $f^{-1}(x) = e^x + 1$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: `The table gives some values of $f(x)$ and $f^{-1}(x)$.\n\n| $x$ | $f(x)$ |\n|---|---|\n| $1$ | $4$ |\n| $2$ | $7$ |\n| $3$ | $10$ |\n\n$f^{-1}(7)$ equals:`, optionA: "$2$", optionB: "$7$", optionC: "$3$", optionD: "$1/7$", correctOption: "A", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $f(2) = 7$, so $f^{-1}(7) = 2$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "If $f$ passes through $(3, 8)$, then $f^{-1}$ passes through:", optionA: "$(3, 8)$", optionB: "$(8, 3)$", optionC: "$(3, 1/8)$", optionD: "$(-3, -8)$", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Inverse swaps coordinates: $(x, y) \\to (y, x)$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "The inverse of $f(x) = \\dfrac{2x + 1}{3}$ is:", optionA: "$(3x - 1)/2$", optionB: "$(3x + 1)/2$", optionC: "$(2x - 1)/3$", optionD: "$2x - 3$", correctOption: "A", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $y = (2x + 1)/3 \\Rightarrow 3y = 2x + 1 \\Rightarrow x = (3y - 1)/2$.\n\n**Answer: A**", subtopicSlugs: S },
    // Hard
    { content: "For $f: [-\\pi/2, \\pi/2] \\to \\mathbb{R}$, $f(x) = \\sin x$, the inverse is commonly called:", optionA: "$\\cos^{-1} x$", optionB: "$\\sin^{-1} x$", optionC: "$1/\\sin x$", optionD: "$-\\sin x$", correctOption: "B", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** With the standard restriction, the inverse is $\\sin^{-1}$ (also written $\\arcsin$).\n\n**Answer: B**", subtopicSlugs: S },
    { content: "If $f$ is strictly decreasing on an interval, then $f^{-1}$ is:", optionA: "Strictly increasing", optionB: "Strictly decreasing", optionC: "Constant", optionD: "Undefined", correctOption: "B", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** Reflection in $y = x$ preserves monotonicity direction: decreasing stays decreasing.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "The graphs of $f$ and $f^{-1}$ always intersect on:", optionA: "$x$-axis", optionB: "$y$-axis", optionC: "Line $y = x$", optionD: "Never (no guarantee)", correctOption: "D", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** While many intersection points lie on $y = x$, intersection is not guaranteed for all $f$ and $f^{-1}$.\n\n**Answer: D**", subtopicSlugs: S },
    { content: "For $f: (1, \\infty) \\to \\mathbb{R}$, $f(x) = 1/(x - 1)$, the inverse is:", optionA: "$1/x + 1$", optionB: "$1/(x + 1)$", optionC: "$(x + 1)/x$", optionD: "$x - 1$", correctOption: "A", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** $y = 1/(x - 1)$, so $x - 1 = 1/y$, hence $x = 1/y + 1$. Thus $f^{-1}(x) = 1/x + 1$.\n\n**Answer: A**", subtopicSlugs: S },
  ];
  const shortAnswer: FR[] = [
    { content: "Find $f^{-1}(x)$ for $f(x) = 4x - 7$.", marks: 2, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Let $y = 4x - 7$, so $x = (y + 7)/4$.\n\n**Step 2 (1 mark):** $f^{-1}(x) = (x + 7)/4$.", subtopicSlugs: S },
    { content: "Find $f^{-1}(x)$ for $f(x) = e^{x + 2}$.", marks: 2, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** $y = e^{x + 2} \\Rightarrow x + 2 = \\ln y$.\n\n**Step 2 (1 mark):** $f^{-1}(x) = \\ln x - 2$.", subtopicSlugs: S },
    { content: "Find $f^{-1}(x)$ for $f(x) = \\dfrac{x + 3}{x - 1}$, $x \\neq 1$.", marks: 4, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Set $y = \\dfrac{x + 3}{x - 1}$.\n\n**Step 2 (1 mark):** Cross-multiply.\n\n$$y(x - 1) = x + 3.$$\n\n**Step 3 (1 mark):** Expand and gather $x$.\n\n$$yx - y = x + 3 \\implies x(y - 1) = y + 3.$$\n\n**Step 4 (1 mark):** Solve.\n\n$$x = \\dfrac{y + 3}{y - 1} \\implies f^{-1}(x) = \\dfrac{x + 3}{x - 1}.$$", subtopicSlugs: S },
    { content: "For $f: [0, \\infty) \\to \\mathbb{R}$, $f(x) = x^2 + 1$, find the inverse, including its domain.", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $y = x^2 + 1 \\Rightarrow x^2 = y - 1$ (take the nonnegative root).\n\n**Step 2 (1 mark):** $x = \\sqrt{y - 1}$, so $f^{-1}(x) = \\sqrt{x - 1}$.\n\n**Step 3 (1 mark):** Domain of $f^{-1}$ is the range of $f$: $[1, \\infty)$.", subtopicSlugs: S },
    { content: "Given $f(x) = \\ln(x - 3) + 2$, find $f^{-1}(x)$.", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Set $y = \\ln(x - 3) + 2$, so $y - 2 = \\ln(x - 3)$.\n\n**Step 2 (1 mark):** Exponentiate: $x - 3 = e^{y - 2}$.\n\n**Step 3 (1 mark):** $x = e^{y - 2} + 3$, so $f^{-1}(x) = e^{x - 2} + 3$.", subtopicSlugs: S },
    { content: "State whether $f(x) = x^3$ is invertible on $\\mathbb{R}$, and if so give the inverse.", marks: 2, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $x^3$ is strictly increasing on $\\mathbb{R}$, hence one-to-one.\n\n**Step 2 (1 mark):** $f^{-1}(x) = \\sqrt[3]{x}$.", subtopicSlugs: S },
    { content: "Sketch $f(x) = 2x + 1$ and its inverse on the same axes, indicating the reflection line.", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $f^{-1}(x) = (x - 1)/2$.\n\n**Step 2 (1 mark):** Line $y = x$ is the reflection axis.\n\n**Step 3 (1 mark):** Sketch: two lines, $f$ steeper with intercept $1$, $f^{-1}$ shallower with intercept $-1/2$, symmetric about $y = x$.", subtopicSlugs: S },
    { content: "For $f(x) = 1 - e^{-x}$, find $f^{-1}(x)$ stating any domain restriction.", marks: 3, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** Set $y = 1 - e^{-x}$, so $e^{-x} = 1 - y$.\n\n**Step 2 (1 mark):** Take log: $-x = \\ln(1 - y)$, so $x = -\\ln(1 - y)$.\n\n**Step 3 (1 mark):** $f^{-1}(x) = -\\ln(1 - x)$, domain $x < 1$ (range of $f$).", subtopicSlugs: S },
    { content: "Verify that $f(x) = 5x - 2$ and $g(x) = (x + 2)/5$ are inverses of each other.", marks: 3, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** Compute $f(g(x))$.\n\n$$f(g(x)) = 5 \\cdot \\dfrac{x + 2}{5} - 2.$$\n\n**Step 2 (1 mark):** Simplify: $= (x + 2) - 2 = x$. Ō£ō\n\n**Step 3 (1 mark):** Also $g(f(x)) = \\dfrac{(5x - 2) + 2}{5} = x$. Ō£ō ŌĆö they are mutual inverses.", subtopicSlugs: S },
    { content: "For $f: [0, \\infty) \\to \\mathbb{R}$, $f(x) = \\sqrt{x + 4} - 1$, find the inverse and its domain.", marks: 4, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** Set $y = \\sqrt{x + 4} - 1$.\n\n**Step 2 (1 mark):** Rearrange: $y + 1 = \\sqrt{x + 4}$.\n\n**Step 3 (1 mark):** Square: $x + 4 = (y + 1)^2$, so $x = (y + 1)^2 - 4$.\n\n**Step 4 (1 mark):** $f^{-1}(x) = (x + 1)^2 - 4$. Range of $f$: $f(0) = \\sqrt 4 - 1 = 1$, then increasing to $\\infty$. So domain of $f^{-1}$ is $[1, \\infty)$.", subtopicSlugs: S },
  ];
  const extendedResponse: FR[] = [
    { content: "Consider $f(x) = 2 e^{x - 1} + 3$.\n\n**a.** State the range of $f$. (2 marks)\n\n**b.** Explain why $f$ is one-to-one. (2 marks)\n\n**c.** Find $f^{-1}(x)$. (3 marks)\n\n**d.** State the domain of $f^{-1}$. (2 marks)\n\n**e.** Verify that $f(f^{-1}(5)) = 5$. (2 marks)", marks: 11, difficulty: "HARD", solutionContent: "**a. (2 marks)**\n\n*Step 1 (1 mark):* $e^{x - 1} > 0$, so $2 e^{x - 1} > 0$.\n\n*Step 2 (1 mark):* Range $(3, \\infty)$.\n\n**b. (2 marks)**\n\n*Step 1 (1 mark):* $e^{x - 1}$ is strictly increasing.\n\n*Step 2 (1 mark):* Multiplying by $2$ and adding $3$ preserves monotonicity, so $f$ is one-to-one.\n\n**c. (3 marks)**\n\n*Step 1 (1 mark):* Set $y = 2 e^{x - 1} + 3$.\n\n*Step 2 (1 mark):* Isolate: $e^{x - 1} = (y - 3)/2$.\n\n*Step 3 (1 mark):* Take log: $x - 1 = \\ln\\!\\left(\\dfrac{y - 3}{2}\\right)$, so $f^{-1}(x) = \\ln\\!\\left(\\dfrac{x - 3}{2}\\right) + 1$.\n\n**d. (2 marks)**\n\n*Step 1 (1 mark):* Domain of $f^{-1}$ = range of $f$.\n\n*Step 2 (1 mark):* Domain: $(3, \\infty)$.\n\n**e. (2 marks)**\n\n*Step 1 (1 mark):* $f^{-1}(5) = \\ln(1) + 1 = 1$.\n\n*Step 2 (1 mark):* $f(1) = 2 e^0 + 3 = 5$. Ō£ō", subtopicSlugs: S },
    { content: "Let $f(x) = x^2 - 4x + 5$.\n\n**a.** Complete the square. (2 marks)\n\n**b.** Explain why $f$ is not one-to-one on $\\mathbb{R}$. (2 marks)\n\n**c.** Restrict $f$ to a suitable domain so that it is one-to-one, then find the inverse on that domain. (4 marks)\n\n**d.** State the domain and range of $f^{-1}$. (2 marks)", marks: 10, difficulty: "HARD", solutionContent: "**a. (2 marks)**\n\n*Step 1 (1 mark):* Group.\n\n$$f(x) = (x^2 - 4x + 4) + 1.$$\n\n*Step 2 (1 mark):* Simplify.\n\n$$f(x) = (x - 2)^2 + 1.$$\n\n**b. (2 marks)**\n\n*Step 1 (1 mark):* The parabola is symmetric about $x = 2$.\n\n*Step 2 (1 mark):* For example, $f(0) = f(4) = 5$, so it's not injective.\n\n**c. (4 marks)**\n\n*Step 1 (1 mark):* Restrict to $[2, \\infty)$.\n\n*Step 2 (1 mark):* Set $y = (x - 2)^2 + 1$, so $(x - 2)^2 = y - 1$.\n\n*Step 3 (1 mark):* $x - 2 = \\sqrt{y - 1}$ (positive root, since $x \\geq 2$).\n\n*Step 4 (1 mark):* $f^{-1}(x) = 2 + \\sqrt{x - 1}$.\n\n**d. (2 marks)**\n\n*Step 1 (1 mark):* Domain of $f^{-1}$ = range of restricted $f$ = $[1, \\infty)$.\n\n*Step 2 (1 mark):* Range of $f^{-1}$ = $[2, \\infty)$.", subtopicSlugs: S },
    { content: "Let $f(x) = \\dfrac{2x - 1}{x + 3}$.\n\n**a.** State the domain of $f$. (2 marks)\n\n**b.** State the horizontal asymptote and hence the range. (3 marks)\n\n**c.** Find the inverse $f^{-1}$. (4 marks)\n\n**d.** State the domain of $f^{-1}$. (2 marks)\n\n**e.** Compute $f(0)$ and $f^{-1}(-1/3)$. (2 marks)", marks: 13, difficulty: "HARD", solutionContent: "**a. (2 marks)**\n\n*Step 1 (1 mark):* Denominator zero at $x = -3$.\n\n*Step 2 (1 mark):* Domain $\\mathbb{R} \\setminus \\{-3\\}$.\n\n**b. (3 marks)**\n\n*Step 1 (1 mark):* Horizontal asymptote $y = 2$ (leading-coefficient ratio).\n\n*Step 2 (1 mark):* $f$ never takes value $2$.\n\n*Step 3 (1 mark):* Range $\\mathbb{R} \\setminus \\{2\\}$.\n\n**c. (4 marks)**\n\n*Step 1 (1 mark):* Set $y = \\dfrac{2x - 1}{x + 3}$.\n\n*Step 2 (1 mark):* Cross-multiply.\n\n$$y(x + 3) = 2x - 1.$$\n\n*Step 3 (1 mark):* Expand and collect $x$.\n\n$$yx + 3y = 2x - 1 \\implies x(y - 2) = -1 - 3y.$$\n\n*Step 4 (1 mark):* Solve.\n\n$$x = \\dfrac{-1 - 3y}{y - 2} = \\dfrac{3y + 1}{2 - y} \\implies f^{-1}(x) = \\dfrac{3x + 1}{2 - x}.$$\n\n**d. (2 marks)**\n\n*Step 1 (1 mark):* Domain of $f^{-1}$ = range of $f$.\n\n*Step 2 (1 mark):* $\\mathbb{R} \\setminus \\{2\\}$.\n\n**e. (2 marks)**\n\n*Step 1 (1 mark):* $f(0) = -1/3$.\n\n*Step 2 (1 mark):* $f^{-1}(-1/3) = 0$ (verifies inverse).", subtopicSlugs: S },
    { content: "Consider $f(x) = \\ln(x + 2)$.\n\n**a.** State the domain of $f$. (1 mark)\n\n**b.** State the range of $f$. (1 mark)\n\n**c.** Find $f^{-1}$. (3 marks)\n\n**d.** State the domain and range of $f^{-1}$. (2 marks)\n\n**e.** Sketch $f$ and $f^{-1}$ on the same axes, including the line $y = x$. (3 marks)\n\n**f.** Show that $f^{-1}(0) = f^{-1}(0)$ ŌĆö i.e. compute $f^{-1}(0)$. (2 marks)", marks: 12, difficulty: "HARD", solutionContent: "**a. (1 mark)**\n\n*Step 1 (1 mark):* $x + 2 > 0 \\Rightarrow x > -2$. Domain $(-2, \\infty)$.\n\n**b. (1 mark)**\n\n*Step 1 (1 mark):* Range $\\mathbb{R}$.\n\n**c. (3 marks)**\n\n*Step 1 (1 mark):* Set $y = \\ln(x + 2)$.\n\n*Step 2 (1 mark):* Exponentiate: $x + 2 = e^y$.\n\n*Step 3 (1 mark):* $f^{-1}(x) = e^x - 2$.\n\n**d. (2 marks)**\n\n*Step 1 (1 mark):* Domain of $f^{-1}$ = $\\mathbb{R}$.\n\n*Step 2 (1 mark):* Range of $f^{-1}$ = $(-2, \\infty)$.\n\n**e. (3 marks)**\n\n*Step 1 (1 mark):* Sketch $f$: asymptote $x = -2$, crosses $(-1, 0)$.\n\n*Step 2 (1 mark):* Sketch $f^{-1}$: asymptote $y = -2$, crosses $(0, -1)$.\n\n*Step 3 (1 mark):* Draw line $y = x$ to show the reflection.\n\n**f. (2 marks)**\n\n*Step 1 (1 mark):* $f^{-1}(0) = e^0 - 2 = 1 - 2$.\n\n*Step 2 (1 mark):* $= -1$.", subtopicSlugs: S },
    { content: "Define $f(x) = \\dfrac{1}{2} x^3 + 1$.\n\n**a.** Show that $f$ is one-to-one on $\\mathbb{R}$. (2 marks)\n\n**b.** Find $f^{-1}(x)$. (3 marks)\n\n**c.** Compute $f^{-1}(5)$ and $f(f^{-1}(5))$. (3 marks)\n\n**d.** Solve $f(x) = f^{-1}(x)$. Hint: use the fact intersections often lie on $y = x$. (4 marks)\n\n**e.** State the domain and range of $f^{-1}$. (2 marks)", marks: 14, difficulty: "HARD", solutionContent: "**a. (2 marks)**\n\n*Step 1 (1 mark):* $x^3$ is strictly increasing on $\\mathbb{R}$.\n\n*Step 2 (1 mark):* Multiplying by $1/2$ and adding $1$ preserves monotonicity, so $f$ is strictly increasing ŌĆö one-to-one.\n\n**b. (3 marks)**\n\n*Step 1 (1 mark):* Set $y = \\tfrac{1}{2} x^3 + 1$.\n\n*Step 2 (1 mark):* Solve: $x^3 = 2(y - 1)$.\n\n*Step 3 (1 mark):* $f^{-1}(x) = \\sqrt[3]{2(x - 1)}$.\n\n**c. (3 marks)**\n\n*Step 1 (1 mark):* $f^{-1}(5) = \\sqrt[3]{2 \\cdot 4} = \\sqrt[3]{8}$.\n\n*Step 2 (1 mark):* $= 2$.\n\n*Step 3 (1 mark):* $f(2) = \\tfrac{1}{2}(8) + 1 = 5$. Ō£ō\n\n**d. (4 marks)**\n\n*Step 1 (1 mark):* Solve $f(x) = x$ (intersection with $y = x$): $\\tfrac{1}{2} x^3 + 1 = x$.\n\n*Step 2 (1 mark):* Multiply by $2$: $x^3 - 2x + 2 = 0$.\n\n*Step 3 (1 mark):* Try $x = -\\sqrt{2}$: $-2\\sqrt{2} + 2\\sqrt{2} + 2 = 2 \\neq 0$. Numerically, use factoring: the real root is approximately $x \\approx -1.77$.\n\n*Step 4 (1 mark):* So $f(x) = f^{-1}(x)$ at $x \\approx -1.77$ (the only real intersection).\n\n**e. (2 marks)**\n\n*Step 1 (1 mark):* Domain $\\mathbb{R}$ (since $f$ has range $\\mathbb{R}$).\n\n*Step 2 (1 mark):* Range $\\mathbb{R}$.", subtopicSlugs: S },
  ];
  writeQset(OUT("inverse-functions"), { mcq, shortAnswer, extendedResponse });
}

