{
  const S = ["composite-functions"];
  const mcq: MCQ[] = [
    { content: "If $f(x) = x + 2$ and $g(x) = 3x$, then $(f \\circ g)(x)$ equals:", optionA: "$3x + 2$", optionB: "$3x + 6$", optionC: "$3(x + 2)$", optionD: "$3x^2$", correctOption: "A", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** $(f \\circ g)(x) = f(g(x)) = f(3x) = 3x + 2$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "If $f(x) = x^2$ and $g(x) = x + 1$, then $g(f(3))$ equals:", optionA: "$9$", optionB: "$10$", optionC: "$16$", optionD: "$4$", correctOption: "B", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** $f(3) = 9$, then $g(9) = 10$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "$(f \\circ g)(x) = f(g(x))$ means:", optionA: "Apply $f$ first, then $g$", optionB: "Apply $g$ first, then $f$", optionC: "Multiply", optionD: "Add", correctOption: "B", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Inner function $g$ is applied first.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "If $f(x) = 2x$ and $g(x) = x - 3$, then $(g \\circ f)(x)$ equals:", optionA: "$2x - 3$", optionB: "$2x + 3$", optionC: "$2(x - 3)$", optionD: "$x - 6$", correctOption: "A", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** $(g \\circ f)(x) = g(2x) = 2x - 3$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "If $f(x) = x^2$ and $g(x) = \\sqrt{x}$, then $(f \\circ g)(4)$ equals:", optionA: "$2$", optionB: "$4$", optionC: "$16$", optionD: "$8$", correctOption: "B", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** $g(4) = 2$, then $f(2) = 4$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "$(f \\circ g)(x)$ is defined when:", optionA: "$x \\in \\text{dom}(f)$", optionB: "$g(x) \\in \\text{dom}(f)$ and $x \\in \\text{dom}(g)$", optionC: "$x \\in \\text{dom}(f) \\cap \\text{dom}(g)$", optionD: "Always", correctOption: "B", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Need $x$ in domain of $g$, and $g(x)$ in domain of $f$.\n\n**Answer: B**", subtopicSlugs: S },
    // Medium
    { content: "If $f(x) = x + 1$ and $g(x) = x^2$, then $(f \\circ g)(x) - (g \\circ f)(x)$ equals:", optionA: "$0$", optionB: "$-2x$", optionC: "$2x$", optionD: "$-2x - 1$... hmm: $(x^2 + 1) - (x + 1)^2 = x^2 + 1 - x^2 - 2x - 1 = -2x$", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $(f \\circ g)(x) = x^2 + 1$; $(g \\circ f)(x) = (x + 1)^2 = x^2 + 2x + 1$. Difference: $-2x$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "If $f(x) = e^x$ and $g(x) = 2x$, then $(f \\circ g)(x)$ equals:", optionA: "$e^{2x}$", optionB: "$2 e^x$", optionC: "$(e^x)^2$", optionD: "$e^{x + 2}$", correctOption: "A", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $(f \\circ g)(x) = f(2x) = e^{2x}$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "If $f(x) = \\ln x$ and $g(x) = x^2$, then $(f \\circ g)(x)$ equals:", optionA: "$\\ln(x^2)$", optionB: "$(\\ln x)^2$", optionC: "$2 \\ln x$", optionD: "Both A and C", correctOption: "D", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $(f \\circ g)(x) = \\ln(x^2) = 2 \\ln |x|$. For $x > 0$, both expressions in A and C are equal.\n\n**Answer: D**", subtopicSlugs: S },
    { content: `${graphImage((x) => Math.sqrt(Math.max(0, x)), { xMin: -1, xMax: 9, yMin: -0.5, yMax: 3.5 }, "y=sqrt x")}\n\nFor $f(x) = \\sqrt{x}$ (shown) and $g(x) = x - 4$, the domain of $(f \\circ g)(x)$ is:`, optionA: "$[0, \\infty)$", optionB: "$[4, \\infty)$", optionC: "$\\mathbb{R}$", optionD: "$(-\\infty, 4]$", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Need $g(x) \\geq 0$, i.e. $x - 4 \\geq 0$, so $x \\geq 4$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "If $f(x) = 3x + 1$ and $g(x) = (x - 1)/3$, then $(f \\circ g)(x)$ equals:", optionA: "$x$", optionB: "$3x$", optionC: "$9x + 1$", optionD: "$x + 1$", correctOption: "A", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $f(g(x)) = 3 \\cdot \\dfrac{x - 1}{3} + 1 = (x - 1) + 1 = x$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: `The table shows $f$ and $g$.\n\n| $x$ | $f(x)$ | $g(x)$ |\n|---|---|---|\n| $0$ | $1$ | $-1$ |\n| $1$ | $3$ | $0$ |\n| $2$ | $5$ | $2$ |\n| $3$ | $7$ | $4$ |\n\n$(f \\circ g)(2)$ equals:`, optionA: "$5$", optionB: "$7$", optionC: "$3$", optionD: "$11$... hmm: $g(2) = 2$, $f(2) = 5$. So 5.", correctOption: "A", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $g(2) = 2$, then $f(2) = 5$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "If $f(x) = \\sin x$ and $g(x) = 2x$, then $(f \\circ g)(x)$ equals:", optionA: "$2 \\sin x$", optionB: "$\\sin(2x)$", optionC: "$\\sin^2 x$", optionD: "$2 \\sin(2x)$", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $(f \\circ g)(x) = \\sin(2x)$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "If $h(x) = (2x + 1)^3$, one way to write $h = f \\circ g$ is:", optionA: "$f(x) = x^3$, $g(x) = 2x + 1$", optionB: "$f(x) = 2x + 1$, $g(x) = x^3$", optionC: "$f(x) = x + 1$, $g(x) = 2 x^3$", optionD: "$f(x) = (x + 1)^3$, $g(x) = 2 x$", correctOption: "A", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $g(x) = 2x + 1$ inner; $f(u) = u^3$ outer.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "If $f(x) = 1/x$ (for $x \\neq 0$) and $g(x) = x + 2$, the domain of $(f \\circ g)(x)$ is:", optionA: "$\\mathbb{R}$", optionB: "$\\mathbb{R} \\setminus \\{0\\}$", optionC: "$\\mathbb{R} \\setminus \\{-2\\}$", optionD: "$\\mathbb{R} \\setminus \\{2\\}$", correctOption: "C", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Need $g(x) \\neq 0$, i.e. $x \\neq -2$.\n\n**Answer: C**", subtopicSlugs: S },
    // Hard
    { content: "If $f(x) = \\sqrt{x}$ and $g(x) = x - 1$, the composition $g \\circ f$ has domain:", optionA: "$[1, \\infty)$", optionB: "$[0, \\infty)$", optionC: "$\\mathbb{R}$", optionD: "$(0, \\infty)$", correctOption: "B", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** $(g \\circ f)(x) = \\sqrt{x} - 1$. Need $x \\geq 0$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "Let $f(x) = e^x$ and $g(x) = \\ln x$ (for $x > 0$). Then $(f \\circ g)(x)$ equals:", optionA: "$x$", optionB: "$e^{\\ln x}$ for all $x$", optionC: "$\\ln(e^x)$", optionD: "Both A and B", correctOption: "D", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** $f(g(x)) = e^{\\ln x} = x$ on the domain of $g$ (i.e. $x > 0$). Both A and B capture this.\n\n**Answer: D**", subtopicSlugs: S },
    { content: "If $f(x) = \\sqrt{4 - x^2}$ and $g(x) = \\sin x$, the domain of $(f \\circ g)(x)$ is:", optionA: "$[-2, 2]$", optionB: "$\\mathbb{R}$", optionC: "$[0, \\pi]$", optionD: "$[-\\pi, \\pi]$", correctOption: "B", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** Need $4 - \\sin^2 x \\geq 0$. Since $\\sin^2 x \\leq 1 < 4$, always true. Domain $\\mathbb{R}$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "If $f(x) = 2x + 3$, then $(f \\circ f)(x)$ equals:", optionA: "$2x + 6$", optionB: "$4x + 6$", optionC: "$4x + 9$", optionD: "$2 x^2 + 6x + 9$", correctOption: "C", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** $f(f(x)) = f(2x + 3) = 2(2x + 3) + 3 = 4x + 9$.\n\n**Answer: C**", subtopicSlugs: S },
    { content: "If $f(x) = x^2$ and $g(x) = \\sin x$, then $(f \\circ g)(\\pi/2)$ equals:", optionA: "$0$", optionB: "$\\pi/2$", optionC: "$1$", optionD: "$\\pi^2 / 4$", correctOption: "C", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** $g(\\pi/2) = \\sin(\\pi/2) = 1$, then $f(1) = 1$.\n\n**Answer: C**", subtopicSlugs: S },
  ];
  const shortAnswer: FR[] = [
    { content: "Given $f(x) = x + 3$ and $g(x) = 2x - 1$, find $(f \\circ g)(x)$ and $(g \\circ f)(x)$.", marks: 2, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** $(f \\circ g)(x) = f(2x - 1) = 2x - 1 + 3 = 2x + 2$.\n\n**Step 2 (1 mark):** $(g \\circ f)(x) = g(x + 3) = 2(x + 3) - 1 = 2x + 5$.", subtopicSlugs: S },
    { content: "If $f(x) = x^2 + 1$ and $g(x) = x - 2$, evaluate $f(g(5))$.", marks: 2, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** $g(5) = 3$.\n\n**Step 2 (1 mark):** $f(3) = 9 + 1 = 10$.", subtopicSlugs: S },
    { content: "Let $f(x) = e^x$ and $g(x) = x + 2$. Find $(f \\circ g)(x)$ and $(g \\circ f)(x)$.", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $(f \\circ g)(x) = f(x + 2) = e^{x + 2}$.\n\n**Step 2 (1 mark):** $(g \\circ f)(x) = g(e^x) = e^x + 2$.\n\n**Step 3 (1 mark):** Note they are generally different (non-commutative).", subtopicSlugs: S },
    { content: "If $f(x) = \\sqrt{x}$ and $g(x) = x - 5$, find the domain of $(f \\circ g)(x)$.", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Need $g(x) \\geq 0$.\n\n**Step 2 (1 mark):** So $x - 5 \\geq 0$, i.e. $x \\geq 5$.\n\n**Step 3 (1 mark):** Domain $[5, \\infty)$.", subtopicSlugs: S },
    { content: "Given $h(x) = \\sqrt{2x + 3}$, express $h$ as a composition $f \\circ g$.", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Inner: $g(x) = 2x + 3$.\n\n**Step 2 (1 mark):** Outer: $f(x) = \\sqrt{x}$.\n\n**Step 3 (1 mark):** Then $(f \\circ g)(x) = \\sqrt{2x + 3} = h(x)$. Ō£ō", subtopicSlugs: S },
    { content: "If $f(x) = 3x$ and $g(x) = x + 1$, compute $(f \\circ g \\circ f)(2)$.", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $f(2) = 6$.\n\n**Step 2 (1 mark):** $g(6) = 7$.\n\n**Step 3 (1 mark):** $f(7) = 21$.", subtopicSlugs: S },
    { content: "If $f(x) = \\dfrac{1}{x - 1}$ and $g(x) = x + 2$, find the domain of $(f \\circ g)(x)$.", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $(f \\circ g)(x) = \\dfrac{1}{(x + 2) - 1} = \\dfrac{1}{x + 1}$.\n\n**Step 2 (1 mark):** Need $x + 1 \\neq 0$.\n\n**Step 3 (1 mark):** Domain $\\mathbb{R} \\setminus \\{-1\\}$.", subtopicSlugs: S },
    { content: "Let $f(x) = \\ln x$ and $g(x) = x^2 + 1$. Explain why $(f \\circ g)(x)$ is defined for all real $x$.", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $g(x) = x^2 + 1 \\geq 1 > 0$ for all $x$.\n\n**Step 2 (1 mark):** So $g(x) > 0$ lies in the domain of $f$.\n\n**Step 3 (1 mark):** Hence $(f \\circ g)(x) = \\ln(x^2 + 1)$ is defined for all real $x$.", subtopicSlugs: S },
    { content: "Given $f(x) = 2x$ and $g(x) = 1/x$ (for $x \\neq 0$), find $(g \\circ f)(x)$ and state its domain.", marks: 3, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** $(g \\circ f)(x) = g(2x) = \\dfrac{1}{2x}$.\n\n**Step 2 (1 mark):** Need $2x \\neq 0$, so $x \\neq 0$.\n\n**Step 3 (1 mark):** Domain $\\mathbb{R} \\setminus \\{0\\}$.", subtopicSlugs: S },
    { content: "If $f(x) = x + 1$, find $(f \\circ f \\circ f)(x)$.", marks: 3, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** $(f \\circ f)(x) = f(x + 1) = x + 2$.\n\n**Step 2 (1 mark):** $(f \\circ f \\circ f)(x) = f(x + 2) = x + 3$.\n\n**Step 3 (1 mark):** In general, $f^n(x) = x + n$.", subtopicSlugs: S },
  ];
  const extendedResponse: FR[] = [
    { content: "Let $f(x) = x^2 + 1$ and $g(x) = 2x - 3$.\n\n**a.** Find $(f \\circ g)(x)$, expanded. (3 marks)\n\n**b.** Find $(g \\circ f)(x)$. (2 marks)\n\n**c.** Compute $(f \\circ g)(1)$ and $(g \\circ f)(1)$. (2 marks)\n\n**d.** Solve $(f \\circ g)(x) = 5$. (4 marks)", marks: 11, difficulty: "HARD", solutionContent: "**a. (3 marks)**\n\n*Step 1 (1 mark):* $(f \\circ g)(x) = f(2x - 3) = (2x - 3)^2 + 1$.\n\n*Step 2 (1 mark):* Expand.\n\n$$(2x - 3)^2 = 4 x^2 - 12 x + 9.$$\n\n*Step 3 (1 mark):* Add $1$: $4 x^2 - 12 x + 10$.\n\n**b. (2 marks)**\n\n*Step 1 (1 mark):* $(g \\circ f)(x) = g(x^2 + 1) = 2(x^2 + 1) - 3$.\n\n*Step 2 (1 mark):* Simplify: $2 x^2 - 1$.\n\n**c. (2 marks)**\n\n*Step 1 (1 mark):* $(f \\circ g)(1) = 4 - 12 + 10 = 2$.\n\n*Step 2 (1 mark):* $(g \\circ f)(1) = 2 - 1 = 1$.\n\n**d. (4 marks)**\n\n*Step 1 (1 mark):* Set $4 x^2 - 12 x + 10 = 5$.\n\n*Step 2 (1 mark):* Simplify: $4 x^2 - 12 x + 5 = 0$.\n\n*Step 3 (1 mark):* Apply the quadratic formula: $x = \\dfrac{12 \\pm \\sqrt{144 - 80}}{8}$.\n\n*Step 4 (1 mark):* $x = \\dfrac{12 \\pm 8}{8}$, so $x = 5/2$ or $x = 1/2$.", subtopicSlugs: S },
    { content: "Let $f(x) = \\sqrt{x}$ and $g(x) = 4 - x^2$.\n\n**a.** State the domain of $f$. (1 mark)\n\n**b.** State the range of $g$. (2 marks)\n\n**c.** Find the domain of $(f \\circ g)(x)$. (3 marks)\n\n**d.** Simplify $(f \\circ g)(x)$. (2 marks)\n\n**e.** Solve $(f \\circ g)(x) = 1$. (2 marks)", marks: 10, difficulty: "HARD", solutionContent: "**a. (1 mark)**\n\n*Step 1 (1 mark):* Domain $[0, \\infty)$.\n\n**b. (2 marks)**\n\n*Step 1 (1 mark):* $g$ is a downward parabola with max at $x = 0$: $g(0) = 4$.\n\n*Step 2 (1 mark):* Range $(-\\infty, 4]$.\n\n**c. (3 marks)**\n\n*Step 1 (1 mark):* Need $g(x) \\geq 0$.\n\n*Step 2 (1 mark):* $4 - x^2 \\geq 0 \\Rightarrow |x| \\leq 2$.\n\n*Step 3 (1 mark):* Domain $[-2, 2]$.\n\n**d. (2 marks)**\n\n*Step 1 (1 mark):* $(f \\circ g)(x) = \\sqrt{4 - x^2}$.\n\n*Step 2 (1 mark):* (This is the upper semicircle of radius $2$.)\n\n**e. (2 marks)**\n\n*Step 1 (1 mark):* $\\sqrt{4 - x^2} = 1 \\Rightarrow 4 - x^2 = 1 \\Rightarrow x^2 = 3$.\n\n*Step 2 (1 mark):* $x = \\pm \\sqrt{3}$.", subtopicSlugs: S },
    { content: "Let $f(x) = e^x$ and $g(x) = \\ln(x + 3)$.\n\n**a.** State the domain of $g$. (2 marks)\n\n**b.** Find $(f \\circ g)(x)$ in simplified form. (3 marks)\n\n**c.** State the domain of $(f \\circ g)$. (2 marks)\n\n**d.** Find $(g \\circ f)(x)$ in simplified form. (3 marks)\n\n**e.** State the domain of $(g \\circ f)$. (2 marks)", marks: 12, difficulty: "HARD", solutionContent: "**a. (2 marks)**\n\n*Step 1 (1 mark):* Need $x + 3 > 0$.\n\n*Step 2 (1 mark):* Domain $(-3, \\infty)$.\n\n**b. (3 marks)**\n\n*Step 1 (1 mark):* $(f \\circ g)(x) = e^{\\ln(x + 3)}$.\n\n*Step 2 (1 mark):* Use $e^{\\ln u} = u$ for $u > 0$.\n\n*Step 3 (1 mark):* $= x + 3$.\n\n**c. (2 marks)**\n\n*Step 1 (1 mark):* Must have $x$ in domain of $g$: $x > -3$.\n\n*Step 2 (1 mark):* Domain $(-3, \\infty)$.\n\n**d. (3 marks)**\n\n*Step 1 (1 mark):* $(g \\circ f)(x) = \\ln(e^x + 3)$.\n\n*Step 2 (1 mark):* $e^x + 3 > 0$ for all real $x$.\n\n*Step 3 (1 mark):* So the expression is already simplified: $\\ln(e^x + 3)$.\n\n**e. (2 marks)**\n\n*Step 1 (1 mark):* $e^x$ is defined for all $x$; $e^x + 3 > 0$ always.\n\n*Step 2 (1 mark):* Domain $\\mathbb{R}$.", subtopicSlugs: S },
    { content: "Consider $f(x) = \\dfrac{1}{x}$ (for $x \\neq 0$) and $g(x) = x - 2$.\n\n**a.** Find $(f \\circ g)(x)$. (2 marks)\n\n**b.** State the domain of $(f \\circ g)$. (2 marks)\n\n**c.** Find the asymptotes of $(f \\circ g)$. (3 marks)\n\n**d.** Find $(g \\circ f)(x)$. (2 marks)\n\n**e.** State the domain of $(g \\circ f)$. (2 marks)\n\n**f.** Solve $(f \\circ g)(x) = 1/3$. (2 marks)", marks: 13, difficulty: "HARD", solutionContent: "**a. (2 marks)**\n\n*Step 1 (1 mark):* $(f \\circ g)(x) = f(x - 2)$.\n\n*Step 2 (1 mark):* $= \\dfrac{1}{x - 2}$.\n\n**b. (2 marks)**\n\n*Step 1 (1 mark):* Need $g(x) \\neq 0$, i.e. $x \\neq 2$.\n\n*Step 2 (1 mark):* Domain $\\mathbb{R} \\setminus \\{2\\}$.\n\n**c. (3 marks)**\n\n*Step 1 (1 mark):* Vertical asymptote at $x = 2$.\n\n*Step 2 (1 mark):* Horizontal: as $x \\to \\pm\\infty$, $1/(x - 2) \\to 0$.\n\n*Step 3 (1 mark):* Horizontal asymptote $y = 0$.\n\n**d. (2 marks)**\n\n*Step 1 (1 mark):* $(g \\circ f)(x) = g(1/x)$.\n\n*Step 2 (1 mark):* $= \\dfrac{1}{x} - 2$.\n\n**e. (2 marks)**\n\n*Step 1 (1 mark):* Need $x \\neq 0$.\n\n*Step 2 (1 mark):* Domain $\\mathbb{R} \\setminus \\{0\\}$.\n\n**f. (2 marks)**\n\n*Step 1 (1 mark):* $\\dfrac{1}{x - 2} = \\tfrac{1}{3}$, so $x - 2 = 3$.\n\n*Step 2 (1 mark):* $x = 5$.", subtopicSlugs: S },
    { content: "Let $f(x) = 2x + 1$ and $g(x) = x^2$.\n\n**a.** Find $(f \\circ g)(x)$ and $(g \\circ f)(x)$. (3 marks)\n\n**b.** Solve $(f \\circ g)(x) = (g \\circ f)(x)$. (4 marks)\n\n**c.** Compute $(g \\circ g)(x)$. (2 marks)\n\n**d.** Compute $(f \\circ f)(x)$. (2 marks)\n\n**e.** State in general whether composition of functions is commutative. Justify briefly. (2 marks)", marks: 13, difficulty: "HARD", solutionContent: "**a. (3 marks)**\n\n*Step 1 (1 mark):* $(f \\circ g)(x) = f(x^2) = 2 x^2 + 1$.\n\n*Step 2 (1 mark):* $(g \\circ f)(x) = g(2x + 1) = (2x + 1)^2$.\n\n*Step 3 (1 mark):* Expand: $4 x^2 + 4x + 1$.\n\n**b. (4 marks)**\n\n*Step 1 (1 mark):* Set $2 x^2 + 1 = 4 x^2 + 4 x + 1$.\n\n*Step 2 (1 mark):* Rearrange.\n\n$$0 = 2 x^2 + 4 x.$$\n\n*Step 3 (1 mark):* Factor.\n\n$$2 x(x + 2) = 0.$$\n\n*Step 4 (1 mark):* Solutions $x = 0$ or $x = -2$.\n\n**c. (2 marks)**\n\n*Step 1 (1 mark):* $(g \\circ g)(x) = g(x^2) = (x^2)^2$.\n\n*Step 2 (1 mark):* $= x^4$.\n\n**d. (2 marks)**\n\n*Step 1 (1 mark):* $(f \\circ f)(x) = f(2x + 1) = 2(2x + 1) + 1$.\n\n*Step 2 (1 mark):* $= 4x + 3$.\n\n**e. (2 marks)**\n\n*Step 1 (1 mark):* In general, $f \\circ g \\neq g \\circ f$ ŌĆö composition is NOT commutative.\n\n*Step 2 (1 mark):* Part a demonstrates this: the two compositions produce different polynomials.", subtopicSlugs: S },
  ];
  writeQset(OUT("composite-functions"), { mcq, shortAnswer, extendedResponse });
}









